class Solution:
    def invalidTransactions(self, transactions):
        """
        :type transactions: List[str]
        :rtype: List[str]
        """
        parsed = []
        trans_map = defaultdict(list)

        # Parse transactions
        for trans in transactions:
            name, time, amount, city = trans.split(',')
            time, amount = int(time), int(amount)
            parsed.append((name, time, amount, city, trans))
            trans_map[name].append((time, amount, city))

        result = []

        for name, time, amount, city, trans_str in parsed:
            invalid = False

            # Check if amount exceeds 1000
            if amount > 1000:
                invalid = True
            else:
                # Check if other transactions with same name in different city within 60 minutes
                for other_time, other_amount, other_city in trans_map[name]:
                    if other_city != city and abs(time - other_time) <= 60:
                        invalid = True
                        break

            if invalid:
                result.append(trans_str)

        return result
